package main

import (
	"bytes"
	"encoding/gob"
	"fmt"
	"io/ioutil"
	"os"
	"sync"
)

type Session struct {
	UserID      string
	Preferences map[string]string
	Permissions []string
}

var (
	sessionStore = make(map[string]Session)
	storeMutex   sync.Mutex
)

func saveSessionToFile(sessionID string, session Session) error {
	storeMutex.Lock()
	defer storeMutex.Unlock()

	var buf bytes.Buffer
	enc := gob.NewEncoder(&buf)
	if err := enc.Encode(session); err != nil {
		return err
	}

	filename := fmt.Sprintf("session_%s.gob", sessionID)
	return ioutil.WriteFile(filename, buf.Bytes(), 0600)
}

func loadSessionFromFile(sessionID string) (Session, error) {
	storeMutex.Lock()
	defer storeMutex.Unlock()

	filename := fmt.Sprintf("session_%s.gob", sessionID)
	data, err := ioutil.ReadFile(filename)
	if err != nil {
		return Session{}, err
	}

	var session Session
	buf := bytes.NewBuffer(data)
	dec := gob.NewDecoder(buf)
	if err := dec.Decode(&session); err != nil {
		return Session{}, err
	}

	return session, nil
}

func createSession(sessionID string, userID string, preferences map[string]string, permissions []string) error {
	session := Session{
		UserID:      userID,
		Preferences: preferences,
		Permissions: permissions,
	}
	sessionStore[sessionID] = session
	return saveSessionToFile(sessionID, session)
}

func getSession(sessionID string) (Session, error) {
	if session, exists := sessionStore[sessionID]; exists {
		return session, nil
	}
	return loadSessionFromFile(sessionID)
}

